// Get all items from Merge
const allItems = $input.all();

// Extract data from first item
const extractItem = allItems[0]?.json || {};
const appData = extractItem.data || extractItem;

// Academic search from second item
const searchItem = allItems[1]?.json || {};
const searchResults = searchItem.results || [];

// Get trigger data
const triggerData = $('New Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Document info
const docType = appData.documentType || 'Unknown';
const studentName = appData.studentName || 'Unknown';
const targetSchool = appData.targetSchool || 'Not specified';
const deadline = appData.applicationDeadline || 'N/A';
const appType = appData.applicationType || 'N/A';

// Calculate days until deadline
let daysUntilDeadline = 'N/A';
let deadlineStatus = 'Unknown';
if (deadline && deadline !== 'N/A') {
  try {
    const deadlineDate = new Date(deadline);
    const today = new Date();
    const diffTime = deadlineDate - today;
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    daysUntilDeadline = diffDays;

    if (diffDays < 0) deadlineStatus = '🔴 PASSED';
    else if (diffDays <= 7) deadlineStatus = '🔴 URGENT';
    else if (diffDays <= 30) deadlineStatus = '🟡 SOON';
    else deadlineStatus = '🟢 OK';
  } catch (e) {}
}

// Transcript data
const transcript = appData.transcript || {};
const gpaWeighted = transcript.gpaWeighted || 0;
const gpaUnweighted = transcript.gpaUnweighted || 0;
const gpaScale = transcript.gpaScale || 4.0;
const classRank = transcript.classRank || 0;
const classSize = transcript.classSize || 0;
const apCourses = transcript.apCourses || 0;
const ibCourses = transcript.ibCourses || 0;
const honorsCourses = transcript.honorsCourses || 0;
const rigorousCourses = apCourses + ibCourses + honorsCourses;

// Test score data
const testScore = appData.testScore || {};
const testType = testScore.testType || 'N/A';
const totalScore = testScore.totalScore || 0;
const maxScore = testScore.maxScore || 0;
const testDate = testScore.testDate || 'N/A';
const sections = testScore.sections || [];
const sectionSummary = sections.map(s => `${s.name}: ${s.score}`).join(', ') || 'N/A';

// Recommendation data
const rec = appData.recommendation || {};
const recommenderName = rec.recommenderName || 'N/A';
const recommenderTitle = rec.recommenderTitle || 'N/A';
const strengths = rec.strengths || [];

// Essay data
const essay = appData.essay || {};
const essayPrompt = essay.prompt || 'N/A';
const wordCount = essay.wordCount || 0;
const essayTheme = essay.theme || 'N/A';

// Financial aid
const finAid = appData.financialAid || {};
const efc = finAid.efc || 0;

// Academic resources found
const resourceCount = searchResults.length;
const topResources = searchResults.slice(0, 3).map(r => r.title).join('; ') || 'None found';

// Determine document status
let docStatus = 'Received';
if (docType.toLowerCase().includes('transcript') && gpaWeighted > 0) docStatus = 'Complete';
else if (docType.toLowerCase().includes('test') && totalScore > 0) docStatus = 'Complete';
else if (docType.toLowerCase().includes('recommendation')) docStatus = 'Received';
else if (docType.toLowerCase().includes('essay') && wordCount > 0) docStatus = 'Draft';

return [{
  json: {
    fileName: fileName,
    fileId: fileId,
    documentType: docType,
    studentName: studentName,
    targetSchool: targetSchool,
    applicationDeadline: deadline,
    daysUntilDeadline: daysUntilDeadline,
    deadlineStatus: deadlineStatus,
    applicationType: appType,
    docStatus: docStatus,
    gpaWeighted: gpaWeighted,
    gpaUnweighted: gpaUnweighted,
    gpaScale: gpaScale,
    classRank: classRank > 0 ? `${classRank}/${classSize}` : 'N/A',
    rigorousCourses: rigorousCourses,
    testType: testType,
    totalScore: totalScore,
    maxScore: maxScore,
    testDate: testDate,
    sectionScores: sectionSummary,
    recommenderName: recommenderName,
    recommenderTitle: recommenderTitle,
    strengths: strengths.slice(0, 3).join(', ') || 'N/A',
    essayPrompt: essayPrompt.substring(0, 100),
    wordCount: wordCount,
    essayTheme: essayTheme,
    efc: efc,
    resourceCount: resourceCount,
    topResources: topResources.substring(0, 200),
    processedAt: new Date().toISOString()
  }
}];

